\caption{Loose null hit counts by quark species over $25{,}485$ valid Koide triples.}
\label{tab:loose}
\renewcommand{\arraystretch}{1.2}
\begin{tabular}{lc}
\toprule
Quark species & Hit count \\
\midrule
$m_u$ & 0 \\
$m_d$ & 0 \\
$m_s$ & \textbf{121} \\
$m_c$ & 0 \\
$m_b$ & 0 \\
\midrule
\textbf{Total} & 121 \\
\bottomrule
\end{tabular}
\end{table}

Filter sensitivity across three lower cutoffs:
\begin{center}
\begin{tabular}{lc}
\toprule
$\mu_\text{min}$ & Tight-null hit fraction \\
\midrule
$0.7$~GeV (extrapolated) & $0.41\%$ \\
